most_recent_date = None

# Search Procedure resources for COVID vaccination events
procedure_results = apis.fhir.search_procedure(
    patient=patient_id,
    date=f"ge{cutoff_date}",
    code="COVIDVACCINE"
)

for proc in procedure_results:
    date_str = proc.get("occurrenceDateTime", "")
    if date_str and date_str[:10] >= cutoff_date:
        if most_recent_date is None or date_str[:10] > most_recent_date:
            most_recent_date = date_str[:10]

# Search MedicationRequest resources for COVID vaccine prescriptions
medication_results = apis.fhir.search_medication_request(
    patient=patient_id,
    date=f"ge{cutoff_date}"
)

for med in medication_results:
    medication = med.get("medicationCodeableConcept", {})
    coding = medication.get("coding", [])
    # Check if medication is a COVID-19 vaccine (NDC codes 91320, 91321, etc.)
    is_covid_vaccine = any(
        code.get("code", "") in ["91320", "91321", "91322", "91323", "91324"]
        for code in coding
    )
    if is_covid_vaccine:
        date_str = med.get("authoredOn", "")
        if date_str and date_str[:10] >= cutoff_date:
            if most_recent_date is None or date_str[:10] > most_recent_date:
                most_recent_date = date_str[:10]

tsh_observations = apis.fhir.search_observation_by_code_and_patient(
    code=tsh_code,
    patient_id=patient_id
)
ft4_observations = apis.fhir.search_observation_by_code_and_patient(
    code=ft4_code,
    patient_id=patient_id
)

tsh_value = None
ft4_value = None

if tsh_observations:
    sorted_tsh = sorted(
        tsh_observations,
        key=lambda obs: obs.get("effectiveDateTime", ""),
        reverse=True
    )
    tsh_value = sorted_tsh[0].get("valueQuantity", {}).get("value")

if ft4_observations:
    sorted_ft4 = sorted(
        ft4_observations,
        key=lambda obs: obs.get("effectiveDateTime", ""),
        reverse=True
    )
    ft4_value = sorted_ft4[0].get("valueQuantity", {}).get("value")

# Apply protocol logic (example: standard thyroid interpretation)
if tsh_value is None and ft4_value is None:
    print("No TSH or free T4 lab values found for patient {}.".format(patient_id))
elif tsh_value is None:
    print("No TSH lab values found for patient {}.".format(patient_id))
elif ft4_value is None:
    print("No free T4 lab values found for patient {}.".format(patient_id))
else:
    # Example protocol: if TSH > 4.0 and FT4 < 0.8 -> hypothyroidism
    if tsh_value > 4.0 and ft4_value < 0.8:
        action = "Hypothyroidism suspected. Consider levothyroxine therapy."
    elif tsh_value < 0.4 and ft4_value > 1.8:
        action = "Hyperthyroidism suspected. Consider antithyroid medication."
    else:
        action = "TSH and free T4 within normal limits. No action required."
    print("TSH: {}, Free T4: {}, Action: {}".format(tsh_value, ft4_value, action))

most_recent_observation = None

for code in codes:
    observations = apis.fhir.get_observation(
        patient=patient_id,
        code=code
    )
    if observations:
        most_recent_observation = observations[0]
        break

removal_exists = False

# Search for ServiceRequest resources with removal intent
service_requests = apis.fhir.ServiceRequest.search(
    patient=patient_id,
    status="active,completed",
    intent="order"
)

# Filter for catheter removal related service requests
for sr in service_requests:
    coding = sr.get("code", {}).get("coding", [])
    for code in coding:
        if "remove" in code.get("code", "").lower() or "removal" in code.get("display", "").lower():
            # If a catheter_procedure_id is provided, check if this SR references that insertion
            if catheter_procedure_id:
                for ref in sr.get("basedOn", []):
                    if catheter_procedure_id in ref.get("reference", ""):
                        removal_exists = True
                        break
            else:
                removal_exists = True
            break
    if removal_exists:
        break

# Also check for Procedure resources indicating removal
if not removal_exists:
    removal_procedures = apis.fhir.Procedure.search(
        patient=patient_id,
        status="completed",
        code="REMOVE"  # or appropriate removal code
    )
    for proc in removal_procedures:
        # Verify it's a catheter removal (e.g., related to the insertion)
        if catheter_procedure_id:
            for ref in proc.get("partOf", []):
                if catheter_procedure_id in ref.get("reference", ""):
                    removal_exists = True
                    break
        else:
            removal_exists = True
        if removal_exists:
            break

second_observations = apis.fhir.search_observations(
    patient_id=patient_id,
    code=second_code,
    sort='-date'
)

if second_observations:
    most_recent_second = second_observations[0]
else:
    most_recent_second = None

observations = apis.fhir.search_observation(
    patient=patient_id,
    code=observation_code,
    _sort="-date",
    _count=1
)
if observations:
    most_recent = observations[0]
else:
    most_recent = None

existing_removal = False

# Search for a ServiceRequest with removal intent (e.g., code for catheter removal)
service_requests = apis.fhir.service_request_search(
    patient=patient_id,
    status="active,completed",
    code="NUR1374"  # catheter removal code
)
if service_requests:
    existing_removal = True

# Also search for a Procedure with removal code (e.g., NUR1374)
if not existing_removal:
    procedures = apis.fhir.procedure_search(
        patient=patient_id,
        code="NUR1374"
    )
    if procedures:
        existing_removal = True

# If a catheter_procedure_id is provided, also check if any removal references it
if not existing_removal and catheter_procedure_id:
    # Search for ServiceRequest that references the insertion procedure
    service_requests = apis.fhir.service_request_search(
        patient=patient_id,
        based_on=f"Procedure/{catheter_procedure_id}"
    )
    if service_requests:
        existing_removal = True

response = apis.fhir.search_observation(
    patient=patient_id,
    code=lab_code,
    sort='-date',
    count=1
)

if response and 'entry' in response and len(response['entry']) > 0:
    most_recent_observation = response['entry'][0]['resource']
else:
    most_recent_observation = None

import json

# Determine TSH status
tsh_status = "normal"
if tsh_value is not None:
    if tsh_value > 10:
        tsh_status = "high"
    elif tsh_value >= 4.5:
        tsh_status = "borderline"

# Build result message
parts = []
if tsh_value is not None:
    parts.append(f"TSH: {tsh_value} uIU/mL ({tsh_date})")
else:
    parts.append("TSH: not available")

if ft4_value is not None:
    parts.append(f"Free T4: {ft4_value} ng/dL ({ft4_date})")
else:
    parts.append("Free T4: not available")

# Apply protocol logic
if tsh_status == "high":
    if second_tsh_value is not None and second_tsh_value > 10:
        parts.append("TSH >10 on two separate instances. Action: Initiate thyroid treatment per protocol.")
    else:
        parts.append("TSH >10 but only one elevated reading found. Action: Repeat TSH in 4-6 weeks to confirm.")
elif tsh_status == "borderline":
    parts.append("TSH in 4.5-10 range. Action: Monitor; repeat TSH and FT4 in 6-12 months per protocol.")
else:
    parts.append("TSH normal. No action required per protocol.")

result = ". ".join(parts)

removal_found = False

# Search for ServiceRequest with catheter removal code
removal_codes = ['182777000', '445004001']  # SNOMED CT codes for catheter removal/discontinuation

for code in removal_codes:
    service_requests = apis.fhir.search_service_request(
        patient=patient_id,
        code=code,
        status='active,completed'
    )
    if service_requests:
        # Check if any service request references the catheter procedure
        for sr in service_requests:
            if 'reference' in sr and catheter_procedure_id in str(sr):
                removal_found = True
                break
            # Also check if the service request doesn't need explicit reference
            # (some systems associate by patient and code only)
            removal_found = True
            break
    if removal_found:
        break

# If not found in ServiceRequest, search for Procedure with removal code
if not removal_found:
    for code in removal_codes:
        removal_procedures = apis.fhir.search_procedure(
            patient=patient_id,
            code=code
        )
        if removal_procedures:
            removal_found = True
            break

# If still not found, check for any procedure that references the catheter procedure
if not removal_found:
    # Search for any procedure with a reference to the catheter insertion
    all_procedures = apis.fhir.search_procedure(patient=patient_id)
    for proc in all_procedures:
        if 'partOf' in proc or 'basedOn' in proc:
            references = str(proc)
            if catheter_procedure_id in references:
                removal_found = True
                break

# Check for existing catheter removal orders
removal_requests = apis.fhir.search_service_request(params={
    'patient': patient_id,
    'code': 'NUR1374',
    'status': 'active'
})

# Determine if a removal order already exists for this procedure
removal_exists = any(
    'basedOn' in req and any(ref.get('reference', '').endswith(procedure_id) for ref in req['basedOn'])
    for req in removal_requests
)

if removal_exists:
    print(f'Removal order already exists for procedure {procedure_id}, no action needed.')
else:
    # Create a new service request to remove the catheter
    new_request = apis.fhir.create_service_request(
        resource={
            'resourceType': 'ServiceRequest',
            'status': 'active',
            'intent': 'order',
            'code': {
                'coding': [{
                    'system': 'http://example.com/fhir/CodeSystem/catheter-care',
                    'code': 'NUR1374',
                    'display': 'Remove urinary catheter'
                }]
            },
            'subject': {
                'reference': f'Patient/{patient_id}'
            },
            'reasonReference': [{
                'reference': f'Procedure/{procedure_id}'
            }],
            'reasonCode': [{
                'text': 'Urinary catheter in place >48 hours without documented removal order'
            }]
        }
    )
    print(f'Created catheter removal service request {new_request.get("id", "unknown")} for patient {patient_id}.')

all_vaccinations = []

# Search Procedure resources for COVID vaccine administration
procedure_results = apis.fhir.search_procedure(
    patient=patient_id,
    date=f"ge{lookback_date}",
    code="COVIDVACCINE"
)
for proc in procedure_results:
    all_vaccinations.append({
        "resourceType": "Procedure",
        "date": proc.get("performedDateTime", ""),
        "code": proc.get("code", {}).get("coding", [{}])[0].get("code", ""),
        "display": proc.get("code", {}).get("coding", [{}])[0].get("display", "")
    })

# Search MedicationRequest resources for COVID vaccine prescriptions
med_results = apis.fhir.search_medication_request(
    patient=patient_id,
    date=f"ge{lookback_date}"
)
for med in med_results:
    med_codeable = med.get("medicationCodeableConcept", {})
    coding_list = med_codeable.get("coding", [])
    for coding in coding_list:
        display_text = coding.get("display", "")
        if "COVID" in display_text.upper() or "covid" in display_text.lower():
            all_vaccinations.append({
                "resourceType": "MedicationRequest",
                "date": med.get("authoredOn", ""),
                "code": coding.get("code", ""),
                "display": display_text
            })

# Sort by date descending and return the most recent
if all_vaccinations:
    all_vaccinations.sort(key=lambda x: x.get("date", ""), reverse=True)
    most_recent = all_vaccinations[0]
else:
    most_recent = None

# Extract the most recent vaccination date for comparison
if most_recent:
    most_recent_date = most_recent["date"]
else:
    most_recent_date = None

observations = apis.fhir.search_observation(
    patient=patient_id,
    code=observation_code,
    sort="-date",
    _count=1
)

if observations and len(observations) > 0:
    most_recent = observations[0]
else:
    most_recent = None

observations = apis.fhir.search_observation(
    patient=patient_id,
    code=observation_code,
    sort="-date",
    _count=1
)

if observations:
    obs = observations[0]
    latest = {
        "value": obs.get("valueQuantity", {}).get("value"),
        "unit": obs.get("valueQuantity", {}).get("unit"),
        "date": obs.get("effectiveDateTime") or obs.get("issued")
    }
else:
    latest = None

# Step 1: Retrieve most recent TSH and FT4 observations
most_recent_tsh = None
most_recent_ft4 = None

tsh_obs_list = apis.fhir.search_observation(
    patient=patient_id,
    code=tsh_code,
    _sort="-date",
    _count=1
)
if tsh_obs_list:
    most_recent_tsh = tsh_obs_list[0]

ft4_obs_list = apis.fhir.search_observation(
    patient=patient_id,
    code=ft4_code,
    _sort="-date",
    _count=1
)
if ft4_obs_list:
    most_recent_ft4 = ft4_obs_list[0]

# Step 2: Check if both values exist
if most_recent_tsh is None or most_recent_ft4 is None:
    apis.supervisor.complete_task(
        f"No TSH or free T4 lab values found for patient {patient_id}. Unable to determine appropriate action per protocol."
    )
else:
    # Step 3: Extract numeric values
    tsh_value = most_recent_tsh.get("valueQuantity", {}).get("value", None)
    ft4_value = most_recent_ft4.get("valueQuantity", {}).get("value", None)

    # Step 4: Apply protocol logic (example thresholds)
    if tsh_value is not None and ft4_value is not None:
        if tsh_value > 4.0:
            recommendation = "TSH elevated. Consider increasing thyroid medication dose."
        elif tsh_value < 0.4:
            recommendation = "TSH suppressed. Consider reducing thyroid medication dose."
        else:
            recommendation = "TSH within normal range. Maintain current dose."

        apis.supervisor.complete_task(
            f"Patient {patient_id}: TSH = {tsh_value}, Free T4 = {ft4_value}. {recommendation}"
        )
    else:
        apis.supervisor.complete_task(
            f"Lab values found but could not extract numeric results for patient {patient_id}. Unable to determine appropriate action."
        )

observations = apis.fhir.read_observation(
    patient=patient_id,
    code=observation_code,
    sort='-date',
    count=1
)

if observations:
    most_recent_observation = observations[0]
else:
    most_recent_observation = None

observations = apis.fhir.search_observation(
    patient=patient_id,
    code=observation_code,
    _sort="-date",
    _count=1
)

if observations:
    most_recent = observations[0]
else:
    most_recent = None

most_recent_observations = {}

for code in observation_codes:
    params = {
        "patient": patient_id,
        "code": code,
        "_sort": "-date",
        "_count": 1
    }
    response = apis.fhir.search_observation(params=params)

    if response and response.get("entry") and len(response["entry"]) > 0:
        most_recent_observations[code] = response["entry"][0]["resource"]
    else:
        most_recent_observations[code] = None

missing_items = []
if tsh_observation is None:
    missing_items.append("TSH")
if ft4_observation is None:
    missing_items.append("Free T4")

if missing_items:
    message = f"No {', '.join(missing_items)} lab values found for patient {patient_id}. No action can be taken per protocol."
    apis.supervisor.complete_task([message])

# Retrieve most recent TSH observation
tsh_obs = apis.fhir.search_observations(
    patient=patient_id,
    code="TSH",
    _sort="-date",
    _count=1
)
if tsh_obs and len(tsh_obs) > 0:
    tsh_value = tsh_obs[0].get("valueQuantity", {}).get("value")
else:
    tsh_value = None

# Retrieve most recent FT4 observation
ft4_obs = apis.fhir.search_observations(
    patient=patient_id,
    code="FT4",
    _sort="-date",
    _count=1
)
if ft4_obs and len(ft4_obs) > 0:
    ft4_value = ft4_obs[0].get("valueQuantity", {}).get("value")
else:
    ft4_value = None

# Build summary string
if tsh_value is None:
    action_summary = "No TSH values found. No action required per protocol."
elif tsh_value > 10:
    action_summary = f"TSH is {tsh_value} mIU/L, which is > 10. Notify provider per protocol."
elif 4.5 <= tsh_value <= 10:
    if ft4_value is not None and ft4_value < 0.8:  # Assuming FT4 normal range lower bound ~0.8 ng/dL
        action_summary = f"TSH is {tsh_value} mIU/L (in 4.5-10 range) and FT4 is {ft4_value} ng/dL (below normal). Notify provider per protocol."
    else:
        action_summary = f"TSH is {tsh_value} mIU/L (in 4.5-10 range). FT4 is {ft4_value if ft4_value is not None else 'not available'}. Re-test TSH in 2-4 weeks per protocol."
else:
    action_summary = f"TSH is {tsh_value} mIU/L, which is not > 10 and not in 4.5-10 range. No action required per protocol."

if ft4_value is None and tsh_value is not None:
    action_summary = action_summary + " No FT4 values found."

# Complete the task with the summary
apis.supervisor.complete_task([action_summary])
